<template>
    <view>
        <u-navbar leftText="返回" :border="true" :placeholder='true' title="お知らせ一覧" :safeAreaInsetTop="true">
            <view class="u-nav-slot" slot="left">
                <image src="../../static/icons/tclose.png" style="width: 60upx;height: 60upx;" mode="" @click="toIndex"></image>
            </view>
            <view class="u-nav-slot" slot="right">
                <image src="../../static/icons/fillSetting.png" style="width: 60upx;height: 60upx;margin-right: 20upx;" @click="toSetting"></image>
                <image src="../../static/icons/addB.png" style="width: 60upx;height: 60upx;" @click="toEdit" mode=""></image>
            </view>
        </u-navbar>
        <view class="content">
            <view class="item" v-for="(item,index) in array">
                <view class="itemLeft" :class="current != index? 'border' : ''" @click="showModual(index)">
                    <image src="../../static/icons/select.png" v-if="current == index" mode=""></image>
                </view>
                <view class="itemRight">
                    <view class="iImage">
                        <u-swiper :list="item.images" height="200" :autoplay="false" ></u-swiper>
                    </view>
                    <view class="iInfo">
                        <view class="info1">
                            <view class="i1Left">
                                <view v-text="item.update_time"></view>
                            </view>
                            <view class="i1Right" v-if="item.is_top">
                                <view>固定</view>
                            </view>
                        </view>
                        <view class="info2" v-text="item.title"></view>
                        <view class="info3" v-text="item.content"></view>
                    </view>
                </view>
            </view>
        </view>
        <u-action-sheet :round="20" :actions="list" :show="show" @select="choose" @close="close"></u-action-sheet>
    </view>
</template>

<script>
    import {getNoticeList,deleteNotice} from '@/api/index.js'
    export default {
        data() {
            return {
                current: 0,
                show:false,
                list: [{
                        name: '編集する',
                        color: '#1D1D1F',
                        fontSize: '20'
                    },
                    {
                        name: 'このクーポンを削除',
                        color: '#D93025',
                        fontSize: '20'
                    },
                    {
                        name: 'キャンセル',
                        color: '#1A73E8',
                        fontSize: '20'
                    }
                ],
                array: [ ]
            }
        },
        created() {
           this.getList() 
        },
        methods: {
            getList(){
              let that = this 
              getNoticeList().then((res) => {
                  console.log(res)
                  if(res.code == 200){
                      that.array = res.data.notices
                  }
              })   
            },
            close(){
                this.show = false
            },
            showModual(e){
                this.current = e
                this.show = true
            },
            choose(e){
                let that = this
                let index = that.current
                console.log(e)
                if(e.name == '編集する'){
                     let params = JSON.stringify(that.array[index]) 
                     uni.navigateTo({
                         url:"edit/edit?source=edit&params="+params
                     })
                     console.log(params)
                }else if(e.name == "このクーポンを削除"){
                    deleteNotice(that.array[index].id).then((res) => {
                        console.log()
                        if(res.code == 200){
                            uni.showToast({
                                title:res.message
                            })
                            that.getList()
                        }else{
                            uni.showToast({
                                title:res.message,
                                icon:"none"
                            })
                        }
                    })
                }
            },
            toSetting(){
                uni.navigateTo({
                    url:"../notice/setting/setting"
                })
            },
            toEdit(){
                uni.navigateTo({
                    url:"../notice/edit/edit?source=add"
                })
            },
            toIndex(){
                uni.switchTab({
                    url:"../index/index"
                })
            }
        }
    }
</script>

<style lang="scss">
    .border {
        border-radius: 8upx;
        opacity: 1;
        border: 2upx solid #707070;
    }

    .item {
        display: flex;
        margin-bottom: 40upx;

        .itemLeft {
            width: 40upx;
            height: 40upx;
            flex-shrink: 0;

            image {
                width: 100%;
                height: 100%;
            }
        }

        .itemRight {
            margin-left: 50upx;
            width: 588upx;
            box-shadow: 0px 0px 20upx 2upx rgba(0, 0, 0, 0.16);
            border-radius: 20upx;
            overflow: hidden;

            .iImage {
                width: 100%;
                height: 394upx;

                image {
                    width: 100%;
                    height: 100%;
                }
            }
        }
    }

    .content {
        box-sizing: border-box;
        padding: 40upx;

        .iInfo {
            box-sizing: border-box;
            padding: 20upx;

            .info2 {
                font-size: 28upx;
                font-family: Hiragino Sans-W5, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
            }

            .info3 {
               font-size: 28upx;
               font-family: Hiragino Sans-W3, Hiragino Sans;
               font-weight: normal;
               color: #707070;
               margin-top: 20upx;

                text {
                    color: #1A73E8;
                }
            }

            .info4 {
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
                margin-top: 20upx;
            }

            .info1 {
                display: flex;
                align-items: center;
                justify-content: space-between;
                margin-bottom: 26upx;

                .i1Left {
                   font-size: 28upx;
                   font-family: Hiragino Sans-W3, Hiragino Sans;
                   font-weight: normal;
                   color: #707070;
                }

                .i1Right {
                    font-size: 24upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #1A73E8;
                    background: #FFFFFF;
                    border: 2upx solid #1A73E8;
                    padding: 8upx 12upx;
                    border-radius: 10upx;
                }
            }

            .info5 {
                display: flex;
                align-items: center;
                justify-content: space-between;
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
                margin-top: 20upx;

                .infoItem {
                    flex: 1;
                }

            }
        }
    }

    .title {
        height: 126upx;
        background: #fff;
        box-shadow: 0px 0px 10upx 2upx rgba(0, 0, 0, 0.16);
        box-sizing: border-box;
        padding: 20upx 30upx;
        display: flex;
        align-items: flex-end;
        justify-content: space-between;

        .titleRight {

            view:first-child {
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #707070;
            }

            view:last-child {
                font-size: 28upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
                text-align: right;
                margin-top: 10upx;
            }
        }

        .titleLeft {
            font-size: 32upx;
            font-family: Hiragino Sans-W5, Hiragino Sans;
            font-weight: bold;
            color: #1D1D1F;
        }
    }
</style>
